// tests/a11y/ai-output-formats.test.ts
import { JSDOM } from 'jsdom';
import { renderAIOutput } from '../lib/renderer';

describe('AI output accessibility structure', () => {
  it('renders markdown table with semantic headers', () => {
    const markdown = \`
| Language | Typing | Performance |
|----------|--------|-------------|
| Python   | Dynamic| Moderate    |
| Go       | Static | High        |
\`;
    const html = renderAIOutput(markdown);
    const dom = new JSDOM(html);
    const doc = dom.window.document;

    expect(doc.querySelector('table')).toBeTruthy();
    expect(doc.querySelector('thead')).toBeTruthy();
    const headers = doc.querySelectorAll('th');
    expect(headers.length).toBe(3);
    expect(headers[0].textContent).toBe('Language');
  });

  it('renders code block in pre > code structure', () => {
    const markdown = '\`\`\`python\nprint("hello")\n\`\`\`';
    const html = renderAIOutput(markdown);
    const dom = new JSDOM(html);
    const pre = dom.window.document.querySelector('pre');
    expect(pre).toBeTruthy();
    const code = pre!.querySelector('code');
    expect(code).toBeTruthy();
    // Should have language class for AT announcement
    expect(code!.className).toContain('language-python');
  });

  it('renders numbered list as ol not plain text', () => {
    const markdown = '1. First step\n2. Second step\n3. Third step';
    const html = renderAIOutput(markdown);
    const dom = new JSDOM(html);
    expect(dom.window.document.querySelector('ol')).toBeTruthy();
    expect(dom.window.document.querySelectorAll('li').length).toBe(3);
  });

  it('adds alt text wrapper for AI-generated images', () => {
    const markdown = '![Diagram showing workflow](data:image/svg+xml;base64,...)';
    const html = renderAIOutput(markdown);
    const dom = new JSDOM(html);
    const img = dom.window.document.querySelector('img');
    expect(img).toBeTruthy();
    expect(img!.getAttribute('alt')).toBeTruthy();
    expect(img!.getAttribute('alt')).not.toBe('');
  });
});
